const risks = $('Fetch New Risk Alerts').all().map(i => i.json);
const resolved = $('Fetch Resolved Issues').all().map(i => i.json);
const expansions = $('Fetch Expansion Wins').all().map(i => i.json);
const renewals = $('Fetch Upcoming Renewals').all().map(i => i.json);

const period = `${$now.minus(7, 'days').format('MMM dd')} - ${$now.format('MMM dd, yyyy')}`;

// Risk summary
const riskSummary = risks.length > 0
  ? risks.map(r => `• ${r.account_name} — ${r.risk_level} risk (${r.reason})`).join('\n')
  : '• No new risk alerts this week 🎉';

const highRiskCount = risks.filter(r => r.risk_level === 'High').length;

// Resolved summary
const resolvedSummary = resolved.length > 0
  ? resolved.map(r => `• ${r.account_name} — ${r.issue_type} resolved`).join('\n')
  : '• No issues resolved this week';

// Expansion summary
const totalExpansionArr = expansions.reduce((sum, e) => sum + (e.amount || 0), 0);
const expansionSummary = expansions.length > 0
  ? expansions.map(e => `• ${e.account_name} — +$${e.amount} ARR`).join('\n')
  : '• No expansion wins this week';

// Renewal summary
const renewalSummary = renewals.length > 0
  ? renewals.map(r => `• ${r.account_name} ($${r.arr}) — renews ${r.renewal_date}`).join('\n')
  : '• No renewals in the next 30 days';

// Build digest
const slackDigest = `📊 *Weekly CS Digest* (${period})\n\n` +
  `*📈 Key Metrics*\n` +
  `• New risk alerts: ${risks.length} (${highRiskCount} high)\n` +
  `• Issues resolved: ${resolved.length}\n` +
  `• Expansion wins: ${expansions.length} (+$${totalExpansionArr} ARR)\n` +
  `• Upcoming renewals (30d): ${renewals.length}\n\n` +
  `*🚨 New Risk Alerts*\n${riskSummary}\n\n` +
  `*✅ Issues Resolved*\n${resolvedSummary}\n\n` +
  `*💰 Expansion Wins*\n${expansionSummary}\n\n` +
  `*🔄 Upcoming Renewals (30 days)*\n${renewalSummary}`;

const htmlDigest = `<h2>Weekly CS Digest (${period})</h2>` +
  `<h3>Key Metrics</h3><ul>` +
  `<li>New risk alerts: ${risks.length} (${highRiskCount} high)</li>` +
  `<li>Issues resolved: ${resolved.length}</li>` +
  `<li>Expansion wins: ${expansions.length} (+$${totalExpansionArr} ARR)</li>` +
  `<li>Upcoming renewals (30d): ${renewals.length}</li></ul>` +
  `<h3>🚨 New Risk Alerts</h3><p>${riskSummary.replace(/\n/g, '<br>')}</p>` +
  `<h3>✅ Issues Resolved</h3><p>${resolvedSummary.replace(/\n/g, '<br>')}</p>` +
  `<h3>💰 Expansion Wins</h3><p>${expansionSummary.replace(/\n/g, '<br>')}</p>` +
  `<h3>🔄 Upcoming Renewals</h3><p>${renewalSummary.replace(/\n/g, '<br>')}</p>`;

return [{ json: { period, slackDigest, htmlDigest, riskCount: risks.length, resolvedCount: resolved.length, expansionCount: expansions.length, renewalCount: renewals.length, totalExpansionArr } }];
